import React, { useEffect, useRef, useState } from "react";
import "./EeshaWalkComponent.css";

// ── Constants ─────────────────────────────────────────────────────────────────
const SENSITIVITY      = 1.8;
const STEP_LEAD        = 1.10;
const FREEZE_THRESHOLD = 2500;   // ms
const FAST_WIN_SIZE    = 5;
const SLOW_WIN_MIN     = 5;      // start detecting after just 5 samples (~0.5 s)
const SLOW_WIN_MAX     = 30;     // full noise-floor window once warmed up
const MIN_STEP_MS      = 350;
const BPM_HISTORY      = 5;      // steps to average for stable BPM

// ── Musical note frequencies ──────────────────────────────────────────────────
// Each theme alternates two harmonically-related notes L→R for a musical feel
const NOTE = {
  C4: 261.6, E4: 329.6, G4: 392.0, A4: 440.0,
  C5: 523.3, E5: 659.3, G5: 784.0, A5: 880.0,
  C6: 1046.5,
};

const THEMES = {
  marimba: { lo: NOTE.C5, hi: NOTE.G5 },   // perfect fifth — warm & pleasant
  chime:   { lo: NOTE.C5, hi: NOTE.E5 },   // major third  — gentle bell
  groove:  { lo: 80,      hi: 0    },       // kick + hi-hat
  rain:    { lo: NOTE.A5, hi: NOTE.C6 },   // high, soft drops
};

// ── Sound synthesis ───────────────────────────────────────────────────────────

function playMarimba(ctx, pan, freq, vol = 0.7) {
  const now = ctx.currentTime;
  const out  = ctx.createGain();
  const pnr  = ctx.createStereoPanner();
  out.gain.setValueAtTime(0, now);
  out.gain.linearRampToValueAtTime(vol, now + 0.004);
  out.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
  pnr.pan.value = pan;

  // Fundamental + inharmonic 4th partial (marimba characteristic)
  [[1, 1.0], [4.07, 0.25]].forEach(([ratio, amp]) => {
    const osc = ctx.createOscillator();
    const g   = ctx.createGain();
    osc.type = "sine";
    osc.frequency.value = freq * ratio;
    g.gain.value = amp;
    osc.connect(g); g.connect(out);
    osc.start(now); osc.stop(now + 0.55);
  });

  out.connect(pnr); pnr.connect(ctx.destination);
}

function playChime(ctx, pan, freq, vol = 0.65) {
  const now = ctx.currentTime;
  const out  = ctx.createGain();
  const pnr  = ctx.createStereoPanner();
  out.gain.setValueAtTime(0, now);
  out.gain.linearRampToValueAtTime(vol, now + 0.003);
  out.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  pnr.pan.value = pan;

  // Bell-like inharmonic partials
  [[1, 1.0], [2.756, 0.4], [5.404, 0.15], [8.933, 0.06]].forEach(([r, a]) => {
    const osc = ctx.createOscillator();
    const g   = ctx.createGain();
    osc.type = "sine";
    osc.frequency.value = freq * r;
    g.gain.value = a;
    osc.connect(g); g.connect(out);
    osc.start(now); osc.stop(now + 1.1);
  });

  out.connect(pnr); pnr.connect(ctx.destination);
}

function playGroove(ctx, pan, isLeft, vol = 0.8) {
  const now = ctx.currentTime;
  const pnr = ctx.createStereoPanner();
  pnr.pan.value = pan;

  if (isLeft) {
    // Kick drum: sine sweep 120→40 Hz, fast decay
    const osc  = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sine";
    osc.frequency.setValueAtTime(120, now);
    osc.frequency.exponentialRampToValueAtTime(40, now + 0.08);
    gain.gain.setValueAtTime(vol, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.18);
    osc.connect(gain); gain.connect(pnr);
    osc.start(now); osc.stop(now + 0.2);
  } else {
    // Hi-hat: bandpass-filtered noise
    const sr       = ctx.sampleRate;
    const bufLen   = Math.round(sr * 0.1);
    const buf      = ctx.createBuffer(1, bufLen, sr);
    const data     = buf.getChannelData(0);
    for (let i = 0; i < bufLen; i++) data[i] = Math.random() * 2 - 1;

    const src  = ctx.createBufferSource();
    const bp   = ctx.createBiquadFilter();
    const gain = ctx.createGain();
    src.buffer = buf;
    bp.type = "bandpass"; bp.frequency.value = 8000; bp.Q.value = 1.2;
    gain.gain.setValueAtTime(vol * 0.6, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08);
    src.connect(bp); bp.connect(gain); gain.connect(pnr);
    src.start(now);
  }

  pnr.connect(ctx.destination);
}

function playRain(ctx, pan, freq, vol = 0.55) {
  const now = ctx.currentTime;
  const out  = ctx.createGain();
  const pnr  = ctx.createStereoPanner();
  // Gentle sine with a very fast attack and medium decay — like a water drop
  out.gain.setValueAtTime(0, now);
  out.gain.linearRampToValueAtTime(vol, now + 0.002);
  out.gain.exponentialRampToValueAtTime(0.001, now + 0.35);
  pnr.pan.value = pan;

  const osc = ctx.createOscillator();
  osc.type = "sine";
  osc.frequency.setValueAtTime(freq, now);
  osc.frequency.exponentialRampToValueAtTime(freq * 0.88, now + 0.1); // slight pitch drop
  osc.connect(out); out.connect(pnr); pnr.connect(ctx.destination);
  osc.start(now); osc.stop(now + 0.4);
}

// Urgent rescue beat for freeze detection
function playRescue(ctx, vol = 0.9) {
  const now = ctx.currentTime;
  for (let i = 0; i < 2; i++) {
    const t = now + i * 0.1;
    const osc  = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "square";
    osc.frequency.value = 1400;
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(vol, t + 0.005);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.07);
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(t); osc.stop(t + 0.08);
  }
}


// ── Component ─────────────────────────────────────────────────────────────────

export default function EeshaWalkComponent({ audioCtx, soundType, onStop }) {
  const [bpm,      setBpm]      = useState("--");
  const [isFrozen, setIsFrozen] = useState(false);
  const [steps,    setSteps]    = useState(0);

  const st = useRef({
    lastStepTime: 0,
    currentBPM:   80,
    stepHistory:  [],   // timestamps of last BPM_HISTORY steps for rolling average
    fastWin:      [],
    slowWin:      [],
    side:         0,
    isRunning:    false,
  });

  const motionRef = useRef(null);

  useEffect(() => {
    const s = st.current;
    s.isRunning = true;

    const init = async () => {
      if (typeof DeviceMotionEvent?.requestPermission === "function") {
        const res = await DeviceMotionEvent.requestPermission();
        if (res !== "granted") { onStop(); return; }
      }
      motionRef.current = handleMotion;
      window.addEventListener("devicemotion", motionRef.current);
      scheduleNextBeat();
    };

    init();

    return () => {
      s.isRunning = false;
      if (motionRef.current) {
        window.removeEventListener("devicemotion", motionRef.current);
        motionRef.current = null;
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Step detection ────────────────────────────────────────────────────────
  function handleMotion(ev) {
    const acc = ev.acceleration;
    if (!acc) return;

    const mag = Math.sqrt((acc.x ?? 0) ** 2 + (acc.y ?? 0) ** 2 + (acc.z ?? 0) ** 2);
    const s   = st.current;

    s.fastWin.push(mag); if (s.fastWin.length > FAST_WIN_SIZE) s.fastWin.shift();
    s.slowWin.push(mag); if (s.slowWin.length > SLOW_WIN_MAX) s.slowWin.shift();

    // Start detecting after SLOW_WIN_MIN samples instead of waiting for the full window.
    // This cuts startup latency from ~5 s to ~0.5 s on slow-reporting phones.
    if (s.slowWin.length < SLOW_WIN_MIN) return;

    const fastAvg = s.fastWin.reduce((a, b) => a + b) / s.fastWin.length;
    const slowAvg = s.slowWin.reduce((a, b) => a + b) / s.slowWin.length;
    const ratio   = fastAvg / (slowAvg + 0.001);

    const now = Date.now();
    if (ratio > SENSITIVITY && now - s.lastStepTime > MIN_STEP_MS) {
      // Rolling BPM average over last BPM_HISTORY steps
      s.stepHistory.push(now);
      if (s.stepHistory.length > BPM_HISTORY + 1) s.stepHistory.shift();

      if (s.stepHistory.length >= 2) {
        const intervals = [];
        for (let i = 1; i < s.stepHistory.length; i++)
          intervals.push(s.stepHistory[i] - s.stepHistory[i - 1]);
        const avgInterval = intervals.reduce((a, b) => a + b) / intervals.length;
        const rawBPM      = Math.min(Math.max(60000 / avgInterval, 40), 160);
        s.currentBPM      = rawBPM * STEP_LEAD;
        setBpm(Math.round(rawBPM));
      }

      s.lastStepTime = now;
      setIsFrozen(false);
      setSteps(n => n + 1);
    }
  }

  // ── Metronome ─────────────────────────────────────────────────────────────
  function scheduleNextBeat() {
    if (!st.current.isRunning) return;

    const s             = st.current;
    const now           = Date.now();
    const timeSinceLast = now - s.lastStepTime;
    let nextInterval;

    if (s.lastStepTime > 0 && timeSinceLast > FREEZE_THRESHOLD) {
      setIsFrozen(true);
      if (audioCtx) playRescue(audioCtx);
      nextInterval = 400;
    } else {
      const isLeft = s.side === 0;
      playBeat(isLeft);
      s.side       = 1 - s.side;
      nextInterval = 60000 / Math.min(Math.max(s.currentBPM, 40), 160);
    }

    setTimeout(scheduleNextBeat, nextInterval);
  }

  function playBeat(isLeft) {
    if (!audioCtx) return;
    const pan    = isLeft ? -0.6 : 0.6;
    const theme  = THEMES[soundType] ?? THEMES.marimba;
    const freq   = isLeft ? theme.lo : theme.hi;

    switch (soundType) {
      case "marimba": playMarimba(audioCtx, pan, freq); break;
      case "chime":   playChime(audioCtx, pan, freq);   break;
      case "groove":  playGroove(audioCtx, pan, isLeft); break;
      case "rain":    playRain(audioCtx, pan, freq);     break;
      default:        playMarimba(audioCtx, pan, freq); break;
    }
  }

  // ── UI ────────────────────────────────────────────────────────────────────
  return (
    <div className={`eesha-walk ${isFrozen ? "eesha-frozen" : ""}`}>

      <div className="eesha-status">
        {isFrozen ? "FREEZE DETECTED" : "WALKING"}
      </div>

      <div className="eesha-bpm-display">
        <span className="eesha-bpm-number">{bpm}</span>
        <span className="eesha-bpm-unit">BPM</span>
      </div>

      <div className="eesha-stat-row">
        <div className="eesha-stat">
          <span className="eesha-stat-value">{steps}</span>
          <span className="eesha-stat-label">Steps</span>
        </div>
        <div className="eesha-stat-divider" />
        <div className="eesha-stat">
          <span className="eesha-stat-value">
            {bpm === "--" ? "--" : Math.round(Number(bpm) * STEP_LEAD)}
          </span>
          <span className="eesha-stat-label">Playing</span>
        </div>
      </div>

      <button className="eesha-stop-btn" onClick={onStop}>
        STOP
      </button>
    </div>
  );
}
